def most_common_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_count = {}

    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    sorted_words = sorted(word_count.items(), key=lambda x: (-x[1], x[0]))

    return sorted_words[0][0]
